package com.school.sis.grade.entity;
import com.school.sis.common.audit.AuditableEntity; import jakarta.persistence.*; import java.math.BigDecimal; import java.util.UUID;
@Entity @Table(name="grading_scale_bands") public class GradingScaleBand extends AuditableEntity {
 @Id private UUID id; @ManyToOne(fetch=FetchType.LAZY,optional=false) @JoinColumn(name="scale_id") private GradingScale scale; @Column(name="minimum_percentage",nullable=false) private BigDecimal minimumPercentage; @Column(name="maximum_percentage",nullable=false) private BigDecimal maximumPercentage; @Column(name="grade_point",nullable=false) private BigDecimal gradePoint; @Enumerated(EnumType.STRING) @Column(nullable=false) private GradeRemark remark;
 @PrePersist void pre(){if(id==null)id=UUID.randomUUID();} public UUID getId(){return id;} public GradingScale getScale(){return scale;} public void setScale(GradingScale v){scale=v;} public BigDecimal getMinimumPercentage(){return minimumPercentage;} public void setMinimumPercentage(BigDecimal v){minimumPercentage=v;} public BigDecimal getMaximumPercentage(){return maximumPercentage;} public void setMaximumPercentage(BigDecimal v){maximumPercentage=v;} public BigDecimal getGradePoint(){return gradePoint;} public void setGradePoint(BigDecimal v){gradePoint=v;} public GradeRemark getRemark(){return remark;} public void setRemark(GradeRemark v){remark=v;}
}
